public boolean isExitByCondition(String condition, Integer taskStatus, String currNodeCode) {
    try {
        if (StrUtil.isBlank(condition)) {
            return false;
        }

        taskStatus = taskStatus == null ? -99 : taskStatus;
        ScriptEngine scriptEngine = SCRIPT_MANAGER.getEngineByName("js"); // JavaScript 引擎
        scriptEngine.put("status", taskStatus);
        scriptEngine.put("nodeCode", currNodeCode);
        boolean result = (Boolean) scriptEngine.eval(condition);
        return result;
    } catch (Exception e) {
        log.error("@isLocked, 锁定条件解析失败, condition = {}, taskStatus = {}", condition, taskStatus, e);
        return true;
    }
}
